import { type IStyleClasses, mapCssProperties } from "@lmb/kitsconcerto-types";

export interface IUseSeparator<T> {
  cssProps: IStyleClasses;
  nativeProps: T;
}

/**
 * Split incoming props into styling-related props (cssProps)
 * and component-specific props (nativeProps).
 */
export const split = <T extends Record<string, any>>(props: Record<string, any>): IUseSeparator<T> => {
  const cssProps: IStyleClasses = {} as IStyleClasses;
  const nativeProps = {} as T;

  for (const key in props) {
    if (key in mapCssProperties) {
      (cssProps as any)[key] = props[key];
    } else {
      (nativeProps as any)[key] = props[key];
    }
  }

  return { cssProps, nativeProps };
};

/**
 * Main hook: returns separated cssProps and nativeProps
 */
export const useSeparator = <T extends Record<string, any>>(props: Record<string, any>): IUseSeparator<T> => {
  return split<T>(props);
};

export default useSeparator;
